@triton.jit
def _qr_decomposition_kernel(A, R, Q, n, block_size):
    # Shared memory for the current block
    shared_A = tl.shared_memory(dtype=tl.float32, shape=(block_size, block_size))
    shared_R = tl.shared_memory(dtype=tl.float32, shape=(block_size, block_size))
    shared_Q = tl.shared_memory(dtype=tl.float32, shape=(block_size, block_size))

    # Thread and block indices
    tx = tl.thread_id(0)
    ty = tl.thread_id(1)
    bx = tl.block_id(0)
    by = tl.block_id(1)

    # Load data into shared memory
    for i in range(0, block_size, 16):
        for j in range(0, block_size, 16):
            if tx + i < n and ty + j < n:
                shared_A[tx + i, ty + j] = A[tx + i, ty + j]

    # Initialize R and Q
    for i in range(0, block_size, 16):
        for j in range(0, block_size, 16):
            if tx + i < n and ty + j < n:
                shared_R[tx + i, ty + j] = shared_A[tx + i, ty + j]
                if i == j:
                    shared_Q[tx + i, ty + j] = 1.0
                else:
                    shared_Q[tx + i, ty + j] = 0.0

    # QR decomposition using Givens rotations
    for k in range(min(n, block_size)):
        # Compute Householder reflector
        if tx == 0 and ty == k:
            # Compute norm of column k
            norm = 0.0
            for i in range(k, n):
                norm += shared_R[i, k] * shared_R[i, k]
            norm = tl.sqrt(norm)

            # Compute reflector
            if norm > 0:
                sign = 1.0 if shared_R[k, k] >= 0 else -1.0
                beta = sign * norm
                alpha = shared_R[k, k] + beta
                shared_R[k, k] = -beta

                # Apply Householder transformation
                for j in range(k + 1, n):
                    dot_product = 0.0
                    for i in range(k, n):
                        dot_product += shared_R[i, j] * shared_R[i, k]
                    dot_product /= alpha

                    for i in range(k, n):
                        shared_R[i, j] -= 2.0 * dot_product * shared_R[i, k]

                # Update Q
                for i in range(n):
                    dot_product = 0.0
                    for j in range(k, n):
                        dot_product += shared_Q[i, j] * shared_R[j, k]
                    dot_product /= alpha

                    for j in range(k, n):
                        shared_Q[i, j] -= 2.0 * dot_product * shared_R[j, k]

    # Store results back to global memory
    for i in range(0, block_size, 16):
        for j in range(0, block_size, 16):
            if tx + i < n and ty + j < n:
                R[tx + i, ty + j] = shared_R[tx + i, ty + j]
                Q[tx + i, ty + j] = shared_Q[tx + i, ty + j]

